namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(new[]
        {
            CreateNotification("Welcome to the notification center!"),
            CreateNotification("Your profile was updated successfully."),
            CreateNotification("New comment on your post."),
        });
    }

    /// <summary>Returns all notifications currently available.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    /// <summary>Returns only notifications with an Id greater than <paramref name="sinceId"/>.</summary>
    public List<Notification> GetSince(int sinceId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > sinceId).ToList();
        }
    }

    /// <summary>
    /// Simulates new notifications arriving at random.
    /// Called internally by the background generator.
    /// </summary>
    public void SimulateIncoming()
    {
        if (Random.Shared.Next(0, 3) == 0) // ~33% chance each tick
        {
            lock (_lock)
            {
                _notifications.Add(
                    CreateNotification($"Server event #{_nextId} detected."));
            }
        }
    }

    private Notification CreateNotification(string message)
    {
        var id = _nextId++;
        return new Notification(id, message, DateTime.UtcNow);
    }
}

namespace NotificationsApp.Services;

/// <summary>
/// Continuously generates fake notifications so the polling page has
/// something new to discover.
/// </summary>
public class NotificationBackgroundService(NotificationService notifications) : BackgroundService
{
    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(4), stoppingToken);
            notifications.SimulateIncoming();
        }
    }
}

